{
  "reconstructed_intent": "用户咨询其购买的重疾险合同中关于轻症赔付的规则，具体想要了解轻症是否可以多次赔付，以及每次赔付的金额是多少。期望回答能够明确说明赔付次数、赔付比例，并提醒以合同条款为准，同时可提供相关限制条件等补充信息。",
  "judge_basis": "基于参考回答（golden answer）评估实际回答的正确性、完整性和有用性。参考回答提供了轻症赔付的详细规则，包括多次赔付、赔付比例、次数上限、间隔期、分组限制、累计上限等。实际回答对照参考回答，评估其是否覆盖了用户问题的核心要点，以及是否提供了准确无误的信息。",
  "judge_method": "采用语义等价与关键点覆盖评估方法。首先从用户问题中提取核心意图点（赔付次数、赔付金额），然后检查实际回答是否明确回答了这些点，内容是否与参考回答一致，是否包含必要的提醒信息。对于非核心补充信息，评估其缺失是否影响回答的有用性。",
  "reasoning_summary": "实际回答明确指出了轻症可以多次赔付，并给出了每次赔付金额的比例范围（20%-30%），同时提及了次数上限和间隔期等限制条件，并提醒用户查阅保险合同条款。这些内容覆盖了用户问题中的核心需求，且与参考回答中的一般规则一致，无错误信息。但实际回答缺失了参考回答中提到的分组限制、累计赔付上限、轻症赔付后重疾保额可能变化等补充细节。尽管如此，这些细节对于回答用户的核心问题并非必需，因此核心需求已满足，整体回答有用且准确。",
  "scenario": "qa_gold_answer",
  "business_expectations": [
    {
      "expectation_id": "明确回答轻症是否可多次赔付",
      "description": "回答应明确告知用户轻症是否可以多次赔付，肯定多次赔付的可能性，并简要说明通常的规则。",
      "acceptance_criteria": "回答中出现类似“可以多次赔付”或“通常可以赔付多次”的肯定性表述。",
      "blocking_level": "blocking"
    },
    {
      "expectation_id": "提供每次轻症赔付的金额比例",
      "description": "回答应提供每次轻症赔付金额相对于基本保额的一般比例，或说明其计算方式。",
      "acceptance_criteria": "回答中包含每次赔付金额的比例，如“20%至30%”，或明确指出金额由合同约定。",
      "blocking_level": "blocking"
    },
    {
      "expectation_id": "说明赔付次数上限和间隔期",
      "description": "回答应提及轻症多次赔付可能存在的次数限制（如3次或5次）和两次赔付之间的间隔期要求。",
      "acceptance_criteria": "回答中出现关于赔付次数上限（如“最多3次”或“3至5次”）和间隔期（如“90天或180天”）的说明。",
      "blocking_level": "blocking"
    },
    {
      "expectation_id": "提醒用户以保险合同为准",
      "description": "保险咨询回答必须包含免责或提醒，告知用户具体赔付条款以保险合同约定为准。",
      "acceptance_criteria": "回答中包含类似“建议查阅您的保险合同条款获取准确信息”或“具体以合同为准”的表述。",
      "blocking_level": "blocking"
    },
    {
      "expectation_id": "覆盖补充规则细节",
      "description": "除了核心的赔付次数和金额外，参考回答中还包括分组限制、累计赔付上限、轻症赔付后重疾保额变化等细节。回答是否覆盖了这些信息以提高完整性。",
      "acceptance_criteria": "回答中提及分组限制、累计上限、重疾保额变化等至少一项补充细节。",
      "blocking_level": "non-blocking"
